
import { library } from '@fortawesome/fontawesome-svg-core';
import { faLongArrowAltRight } 
from '@fortawesome/free-solid-svg-icons'
library.add(faLongArrowAltRight)

import { defineComponent } from 'vue';
import TheMobileMenu from '@/components/Navigation/TheMobileMenu.vue';

export default defineComponent({
  name: 'TheHeader',
  components: {
    TheMobileMenu
  },
  data() {
    return {
      isMobileMenu: false,
      titles: ['Full Stack Developer', 'Tech Geek', 
      'Cyclist', 'In House Dj'],
      currentTitle: ''
    }
  },
  methods: {
    async typeTitle() {
      const delay = ((time: number) => {
        return new Promise((resolve) => {
          setTimeout(() => {
            resolve(true)
          }, time)
        })
      })
      let titleCounter = 0
      for (const title of this.titles) {
        const letters = title.split("");
        this.currentTitle = ''
        let counter = 0
        //write word
        while(counter !== letters.length) {
          for (const letter of letters) {
            this.currentTitle += letter
            await delay(Math.floor(Math.random() * 100) + 50)
            counter++
          }
        }
        await delay(2000)
        //remove word
        while(this.currentTitle.length !== 0) {
          this.currentTitle = this.currentTitle.substring(0, this.currentTitle.length - 1);
          await delay(30)
        }
        await delay(1500)
        titleCounter++
        //restart method
        if (this.titles.length === titleCounter) {
          this.typeTitle()
        }
      }
    }
  },
  mounted() {
    this.typeTitle()
  }
});
